from openai_agents import Agent
from uuid import uuid4

def create_session_agent(user_id: str):
    session_key = f'{user_id}_{uuid4().hex[:8]}'

    return Agent(
        name=f'{user_id}-agent',
        memory_config={
            'type': 'session_scoped',
            'namespace': session_key,
            'ttl_minutes': 60,
            'eviction_policy': 'lru'
        }
    )

async def compress_tool_output(tool_result: str, agent):
    summary = await agent.client.chat.completions.create(
        model='gpt-4o-mini',
        messages=[{
            'role': 'system',
            'content': 'Summarize this tool output to 200 tokens max, preserving key facts:'
        }, {
            'role': 'user',
            'content': tool_result
        }],
        max_tokens=200
    )

    # Store compressed version only
    agent.memory_store.set('tool_last_result', summary.choices[0].message.content)
    return summary.choices[0].message.content
